t.script:
(function () {
    var cards = Array.from(document.querySelectorAll('.lx-sb-card'));
    var total = cards.length;
    var current = 0;
    var correctCount = 0;

    function normalise(str) {
        return str.trim().toLowerCase().replace(/[.,!?;:]$/, '').replace(/\s+/g, ' ');
    }

    function showCard(idx) {
        cards.forEach(function (c) { c.classList.add('d-none'); });
        if (idx < total) {
            cards[idx].classList.remove('d-none');
            initCard(cards[idx]);
        } else {
            showSummary();
        }
    }

    function initCard(card) {
        var tray = card.querySelector('.lx-answer-tray');
        var scramble = card.querySelector('.lx-scramble-tray');
        var feedback = card.querySelector('.lx-sb-feedback');
        var checkBtn = card.querySelector('.lx-check-btn');
        var clearBtn = card.querySelector('.lx-clear-btn');
        var nextBtn = card.querySelector('.lx-next-btn');
        var placeholder = card.querySelector('.lx-tray-placeholder');

        function getAnswerWords() {
            return Array.from(tray.querySelectorAll('.lx-token-tile')).map(function (b) {
                return b.dataset.word;
            });
        }

        function updatePlaceholder() {
            if (tray.querySelectorAll('.lx-token-tile').length === 0) {
                placeholder.style.display = '';
            } else {
                placeholder.style.display = 'none';
            }
        }

        // Move tile from scramble → answer tray
        scramble.querySelectorAll('.lx-token-tile').forEach(function (btn) {
            btn.addEventListener('click', function () {
                if (btn.disabled) return;
                btn.style.display = 'none';
                var clone = btn.cloneNode(true);
                clone.style.display = '';
                clone.style.background = 'rgba(16,185,129,0.15)';
                clone.style.color = '#6ee7b7';
                clone.style.borderColor = 'rgba(16,185,129,0.35)';
                clone.addEventListener('click', function () {
                    if (clone.disabled) return;
                    // Move back to scramble
                    clone.remove();
                    btn.style.display = '';
                    updatePlaceholder();
                });
                tray.appendChild(clone);
                updatePlaceholder();
            });
        });

        checkBtn.addEventListener('click', function () {
            if (card.dataset.done) return;
            var words = getAnswerWords();
            if (words.length === 0) return;

            var answer = normalise(words.join(' '));
            var original = normalise(card.dataset.original);
            var isCorrect = answer === original;

            card.dataset.done = '1';
            if (isCorrect) correctCount++;

            // Disable all tiles
            card.querySelectorAll('.lx-token-tile').forEach(function (b) { b.disabled = true; });
            checkBtn.disabled = true;
            clearBtn.disabled = true;

            feedback.classList.remove('d-none');
            if (isCorrect) {
                card.style.borderColor = 'rgba(34,197,94,0.4)';
                feedback.style.cssText = 'background:rgba(34,197,94,0.1);border:1px solid rgba(34,197,94,0.25);border-radius:10px;padding:10px 14px;font-size:0.88rem;color:#4ade80';
                feedback.innerHTML = '✓ Correct!';
                tray.querySelectorAll('.lx-token-tile').forEach(function (b) {
                    b.style.background = 'rgba(34,197,94,0.2)';
                    b.style.color = '#4ade80';
                    b.style.borderColor = 'rgba(34,197,94,0.5)';
                });
            } else {
                card.style.borderColor = 'rgba(239,68,68,0.35)';
                feedback.style.cssText = 'background:rgba(239,68,68,0.1);border:1px solid rgba(239,68,68,0.25);border-radius:10px;padding:10px 14px;font-size:0.88rem';
                feedback.innerHTML = '✗ Not quite. Correct order: ' + card.dataset.original + '';
            }

            nextBtn.classList.remove('d-none');
        });

        clearBtn.addEventListener('click', function () {
            if (card.dataset.done) return;
            tray.querySelectorAll('.lx-token-tile').forEach(function (b) { b.remove(); });
            scramble.querySelectorAll('.lx-token-tile').forEach(function (b) { b.style.display = ''; });
            updatePlaceholder();
        });

        nextBtn.addEventListener('click', function () {
            current++;
            showCard(current);
        });

        updatePlaceholder();
    }

    function showSummary() {
        document.getElementById('lx-sb-container').style.display = 'none';
        var summary = document.getElementById('lx-sb-summary');
        summary.classList.remove('d-none');
        document.getElementById('lx-sb-score-text').textContent = correctCount + ' / ' + total + ' correct';

        if (correctCount > 0) {
            var csrfTok = (typeof odoo !== 'undefined' ? odoo.csrf_token : '');
            fetch('/my/sentence-builder/score', {
                method: 'POST',
                credentials: 'same-origin',
                headers: {'Content-Type': 'application/json', 'X-CSRF-Token': csrfTok},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', id: 1, params: {correct_count: correctCount}})
            })
            .then(function (r) { return r.json(); })
            .then(function (data) {
                var xp = (data.result || {}).xp_gained || 0;
                if (xp > 0) {
                    document.getElementById('lx-sb-xp-amount').textContent = xp;
                    document.getElementById('lx-sb-xp-gained').classList.remove('d-none');
                }
            })
            .catch(function (err) { console.warn('XP award failed:', err); });
        }
    }

    if (total > 0) { showCard(0); }
})();
